- Secure secret management and least-privilege role checks, combined with structured error handling and logging, providing defense in depth and safe failure.

In production, you should centralize token issuance, support key rotation, validate tokens consistently across services, and add monitoring, rate limiting, and secure defaults.

**PRODUCTION PATTERN**:

```php
<?php
// prod_jwt_middleware.php

require_once __DIR__ . '/vendor/autoload.php';

use Firebase\JWT\JWT;
use Firebase\JWT\Key;

class JwtAuthMiddleware
{
    private string $env;
    private array $keys; // keyId => ["secret" => ..., "alg" => ...]
    private string $expectedIssuer;
    private string $expectedAudience;

    public function __construct(string $env)
    {
        $this->env = $env;

        // ENV-SPECIFIC CONFIGURATION
        $this->expectedIssuer = getenv('JWT_ISSUER') ?: 'https://api.example.com';
        $this->expectedAudience = getenv('JWT_AUDIENCE') ?: 'https://clients.example.com';

        // Support KEY ROTATION via KID
        // In production, load from secure config or JWKS endpoint
        $this->keys = [
            'kid-2025-01' => [
                'secret' => getenv('JWT_SECRET_ACTIVE') ?: 'change_me_in_prod',
                'alg'    => 'HS256',
            ],
            'kid-2024-12' => [
                'secret' => getenv('JWT_SECRET_OLD') ?: 'old_change_me',
                'alg'    => 'HS256',
            ],
        ];
    }

    public function handle(): ?array
    {
        $token = $this->getBearerToken();
        if ($token === null) {
            $this->logSecurityEvent('auth.missing_token');
            http_response_code(401);
            $this->setSecurityHeaders();
            echo json_encode(['error' => 'Authentication required']);
            return null;
        }

        try {
            [$header, $payload] = $this->decodeAndValidate($token);

            // RATE LIMITING and anomaly detection (simplified example)
            $this->applyBasicRateLimiting($payload['sub'] ?? 'unknown');

            // Attach security headers for API clients
            $this->setSecurityHeaders();

            return $payload;
        } catch (Throwable $e) {
            $this->logSecurityEvent('auth.invalid_token', ['reason' => $e->getMessage()]);
            http_response_code(401);
            $this->setSecurityHeaders();
            echo json_encode(['error' => 'Invalid or expired token']);
            return null;
        }
    }

    private function getBearerToken(): ?string
    {
        $authHeader = $_SERVER['HTTP_AUTHORIZATION'] ?? '';
        if (stripos($authHeader, 'Bearer ') === 0) {
            return trim(substr($authHeader, 7));
        }
        return null;
    }

    private function decodeAndValidate(string $jwt): array
    {
        // Parse header to get KID for key rotation
        $parts = explode('.', $jwt);
        if (count($parts) !== 3) {
            throw new Exception('Malformed token');
        }

        $headerJson = base64_decode(strtr($parts[0], '-_', '+/'));
        $header = json_decode($headerJson, true, 512, JSON_THROW_ON_ERROR);

        $kid = $header['kid'] ?? null;
        if (!$kid || !isset($this->keys[$kid])) {
            throw new Exception('Unknown or missing key id');
        }

        $keyConf = $this->keys[$kid];

        // PRIMARY DEFENSE: verify using correct key and algorithm from server-side config
        $decoded = JWT::decode($jwt, new Key($keyConf['secret'], $keyConf['alg']));
        $claims = (array)$decoded;

        $now = time();

        // DEFENSE IN DEPTH: issuer & audience
        if (($claims['iss'] ?? null) !== $this->expectedIssuer) {
            throw new Exception('Invalid issuer');
        }
        if (($claims['aud'] ?? null) !== $this->expectedAudience) {
            throw new Exception('Invalid audience');
        }

        // Time-based checks
        if (isset($claims['nbf']) && $now < (int)$claims['nbf']) {
            throw new Exception('Token not yet valid');
        }
        if (!isset($claims['exp']) || $now >= (int)$claims['exp']) {
            throw new Exception('Token expired');
        }

        // ROLE VALIDATION: whitelist roles
        $role = $claims['role'] ?? 'user';
        $allowedRoles = ['user', 'admin', 'service'];
        if (!in_array($role, $allowedRoles, true)) {
            throw new Exception('Invalid role');
        }

        return [$header, $claims];
    }

    private function applyBasicRateLimiting(string $subject): void
    {
        // Simple in-memory rate limiting placeholder (replace with Redis or similar)
        // This demonstrates the pattern, not production performance.
        static $requests = [];
        $ip = $_SERVER['REMOTE_ADDR'] ?? 'unknown';
        $key = $ip . '|' . $subject;

        $now = time();
        $window = 60; // 1 minute
        $limit = ($this->env === 'production') ? 30 : 100; // per minute

        if (!isset($requests[$key])) {
            $requests[$key] = ['count' => 0, 'start' => $now];
        }

        if ($now - $requests[$key]['start'] > $window) {
            $requests[$key] = ['count' => 0, 'start' => $now];
        }

        $requests[$key]['count']++;
        if ($requests[$key]['count'] > $limit) {
            $this->logSecurityEvent('auth.rate_limit_exceeded', [
                'subject' => $subject,
                'ip' => $ip,
            ]);
            http_response_code(429);
            echo json_encode(['error' => 'Too many requests']);
            exit;
        }
    }

    private function setSecurityHeaders(): void
    {
        // Even for APIs, security headers help against browsers and intermediaries
        header('X-Content-Type-Options: nosniff');
        header('X-Frame-Options: DENY');
        header('Referrer-Policy: no-referrer');
        header('X-XSS-Protection: 1; mode=block');
        header('Content-Security-Policy: default-src\'none\'; frame-ancestors \'' . $this->expectedAudience . '\';');
    }

    private function logSecurityEvent(string $event, array $context = []): void
    {
        $ip = $_SERVER['REMOTE_ADDR'] ?? 'unknown';
        $path = $_SERVER['REQUEST_URI'] ?? '';
        $log = [
            'time' => date('c'),
            'event' => $event,
            'ip' => $ip,
            'path' => $path,
            'context' => $context,
        ];
        // In production, send to centralized logging (ELK, Datadog, etc.)
        error_log('SECURITY: ' . json_encode($log));
    }
}

