// rate_limit.php (simple IP-based rate limit for sensitive actions)
function rate_limited(string $actionKey, int $limit, int $windowSeconds): bool
{
    $ip = $_SERVER['REMOTE_ADDR'] ?? 'unknown';
    $key = "rate_{$actionKey}_{$ip}";
    $now = time();

    if (!isset($_SESSION[$key])) {
        $_SESSION[$key] = ['count' => 1, 'start' => $now];
        return false;
    }

    $entry = &$_SESSION[$key];
    if ($now - $entry['start'] > $windowSeconds) {
        $entry = ['count' => 1, 'start' => $now];
        return false;
    }

    if ($entry['count'] >= $limit) {
        return true;
    }

    $entry['count']++;
    return false;
}

